import { readFileSync, writeFileSync, existsSync, mkdirSync } from "fs";
import { tmpdir } from "os";
import path from "path";
import type { MediaTask } from "@/types/task";

const dataDir = path.join(tmpdir(), "video-data");
const tasksFile = path.join(dataDir, "tasks.json");

function ensureFile() {
  if (!existsSync(dataDir)) mkdirSync(dataDir, { recursive: true });
  if (!existsSync(tasksFile)) writeFileSync(tasksFile, "[]", "utf8");
}

function readTasks(): MediaTask[] {
  ensureFile();
  return JSON.parse(readFileSync(tasksFile, "utf8"));
}

function writeTasks(tasks: MediaTask[]) {
  ensureFile();
  writeFileSync(tasksFile, JSON.stringify(tasks, null, 2), "utf8");
}

export async function listTasks() {
  return readTasks();
}

export async function getTaskById(id: string) {
  return readTasks().find(t => t.id === id) ?? null;
}

export async function saveTask(task: MediaTask) {
  const tasks = readTasks();
  tasks.unshift(task);
  writeTasks(tasks);
  return task;
}

export async function updateTask(updatedTask: MediaTask) {
  const tasks = readTasks().map(t => t.id === updatedTask.id ? updatedTask : t);
  writeTasks(tasks);
  return updatedTask;
}
